import{_ as o}from"./chunks/add_icon.D_Q72d6b.js";import{_ as a,c as d,o as c,aj as i}from"./chunks/framework.CjkNaYQl.js";const f=JSON.parse('{"title":"1. 軟體大師篇","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/1.md","filePath":"advanced/1.md"}'),t={name:"advanced/1.md"};function n(r,e,s,p,l,_){return c(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="_1-軟體大師篇" tabindex="-1">1. 軟體大師篇 <a class="header-anchor" href="#_1-軟體大師篇" aria-label="Permalink to &quot;1. 軟體大師篇&quot;">​</a></h1><h2 id="vision-ocr-和條碼" tabindex="-1">Vision（OCR 和條碼） <a class="header-anchor" href="#vision-ocr-和條碼" aria-label="Permalink to &quot;Vision（OCR 和條碼）&quot;">​</a></h2><p>我們基本上把 <code>Vision</code> 的 <code>Positioning</code> 功能都看過了一次了，在這一章中，我們要看的是 <code>Inspection</code> 的應用。要注意的是，<code>Inspection</code> 不像 <code>Positioning</code> 一樣有一個 <code>Point</code> 的功能，它只會單純做「視覺辨識」這個任務。</p><p>拉入一個 <code>Inspection</code> 並點它的鉛筆圖示以開啟 <code>Vision</code> 編輯畫面，在 <code>視覺應用選擇</code> 中，選擇 <code>AOI辨識</code> → <code>下一步</code>，在這個類別下，我們可以用它來執行辨識文字和數字（即 OCR 光學字元辨識）、讀取二維條碼（Barcode）、三維條碼（QR Code）等。</p><p>左側流程塊中。我們依前面相同的設定方式，就可以設定好 <code>Motion</code> 和 <code>Camera</code> 了，設定好後，在選取 <code>Camera</code> 的情況下，點它底下 <img src="'+o+'" alt="新增流程圖示" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;">，進到 <code>新增視覺流程</code> 頁面中，我們就可以在 <code>Identify</code> 類裡找到先前提到過的那些功能，選擇一個想要辨識的目標後（<code>附加功能</code> 可展開所有功能），點擊 <code>確定</code>，就可以開始設定那類的辨識任務了。</p><h2 id="ai" tabindex="-1">AI+ <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI+&quot;">​</a></h2><p>AI+ 的功能其實很強，而且在高階組的決賽中幾乎必然會用到它，但受限於陽明高中的手臂環境，我們無法用校內的手臂練習到這部分，因此在這章中，我們只講概念，具體操作方式只能在達明的教學課程中學到了。</p><p>AI+ 是 <code>Vision</code> 的一個大類別，它可以做<strong>分類、物件偵測、語義分割、異常偵測、實例分割</strong>，其中我們最常用的是<strong>分類</strong>，它可以藉由拍攝數張照片的方式訓練</p>',8)])])}const u=a(t,[["render",n]]);export{f as __pageData,u as default};
